const body = $input.first().json.body || $input.first().json;
const prompt = body.prompt || "";
const systemPrompt = body.systemPrompt || "You are a helpful AI assistant.";
const extraInputs = body.extraInputs || {};
let fullPrompt = prompt;
if (extraInputs && typeof extraInputs === "object") {
  const extras = Object.entries(extraInputs).filter(([,v]) => v).map(([k,v]) => k + ": " + v).join("
");
  if (extras) fullPrompt = extras + "

" + prompt;
}
return [{ json: { toolId: body.toolId, prompt: fullPrompt, systemPrompt, userId: body.userId || null, apiPayload: { systemInstruction: { parts: [{ text: systemPrompt }] }, contents: [{ role: "user", parts: [{ text: fullPrompt }] }], generationConfig: { maxOutputTokens: 2048 } } } }];

const r = $input.first().json;
const text = r?.candidates?.[0]?.content?.parts?.[0]?.text || "";
return [{ json: { text, success: true } }];

